export const getVocabByCategory = (category: VocabCategory) =>
  vocabulary.filter(w => w.category === category);

export const getVocabByLevel = (level: VocabLevel) =>
  vocabulary.filter(w => w.level === level);

export const getPhrasesByLevel = (level: 'Beginner' | 'Intermediate' | 'Advanced') =>
  phrases.filter(p => p.level === level);
